// src/views/liste.manager.js
import React, { useState, useEffect } from "react";
import Footer from "components/Footers/Footer.js";
import FooterRecharche from "../components/Footers/footer.recharche";
import Navbar from "../components/Navbars/AuthNavbar";
import ManagerCard from "components/Common/managerCard";

export default function ManagersList() {
  const [searchTerm, setSearchTerm] = useState("");
  const [managers, setManagers] = useState([]);
  const [selectedManager, setSelectedManager] = useState(null);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    const mockManagers = [
      {
        id: 1,
        name: "Ahmed Benali",
        role: "Directeur Général",
        profileImage: "https://randomuser.me/api/portraits/men/32.jpg",
        location: "Alger, Algérie",
        rating: 4.9,
        employees: 45,
        restaurantCount: 3,
        experience: "12 ans d'expérience",
        skills: ["Management", "Gestion d'équipe", "Marketing", "Finance"],
        status: "active",
        email: "ahmed.benali@example.com",
        phone: "+213 5 55 55 55 55"
      },
      {
        id: 2,
        name: "Karim El Fassi",
        role: "Directeur des Opérations",
        profileImage: "https://randomuser.me/api/portraits/men/45.jpg",
        location: "Casablanca, Maroc",
        rating: 4.8,
        employees: 32,
        restaurantCount: 2,
        experience: "8 ans d'expérience",
        skills: ["Operations", "Logistique", "Gestion", "RH"],
        status: "active",
        email: "karim.elfassi@example.com",
        phone: "+212 6 12 34 56 78"
      },
      {
        id: 3,
        name: "Sophie Martin",
        role: "Directrice Commerciale",
        profileImage: "https://randomuser.me/api/portraits/women/28.jpg",
        location: "Paris, France",
        rating: 4.7,
        employees: 28,
        restaurantCount: 2,
        experience: "10 ans d'expérience",
        skills: ["Commercial", "Marketing", "Relations clients", "Négociation"],
        status: "active",
        email: "sophie.martin@example.com",
        phone: "+33 6 12 34 56 78"
      },
      {
        id: 4,
        name: "Youssef Mansouri",
        role: "Directeur Financier",
        profileImage: "https://randomuser.me/api/portraits/men/67.jpg",
        location: "Tunis, Tunisie",
        rating: 4.6,
        employees: 22,
        restaurantCount: 1,
        experience: "7 ans d'expérience",
        skills: ["Finance", "Comptabilité", "Audit", "Gestion"],
        status: "inactive",
        email: "youssef.mansouri@example.com",
        phone: "+216 5 55 55 55 55"
      },
      {
        id: 5,
        name: "Laila Hakimi",
        role: "Directrice Marketing",
        profileImage: "https://randomuser.me/api/portraits/women/42.jpg",
        location: "Dubai, UAE",
        rating: 4.9,
        employees: 15,
        restaurantCount: 1,
        experience: "6 ans d'expérience",
        skills: ["Marketing digital", "Réseaux sociaux", "Branding", "Communication"],
        status: "active",
        email: "laila.hakimi@example.com",
        phone: "+971 5 55 55 55 55"
      },
      {
        id: 6,
        name: "Omar Benjelloun",
        role: "Directeur Régional",
        profileImage: "https://randomuser.me/api/portraits/men/89.jpg",
        location: "Rabat, Maroc",
        rating: 4.8,
        employees: 55,
        restaurantCount: 4,
        experience: "15 ans d'expérience",
        skills: ["Management", "Développement", "Stratégie", "Leadership"],
        status: "active",
        email: "omar.benjelloun@example.com",
        phone: "+212 6 98 76 54 32"
      }
    ];
    setManagers(mockManagers);
  }, []);

  const filteredManagers = managers.filter(manager =>
    manager.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    manager.role.toLowerCase().includes(searchTerm.toLowerCase()) ||
    manager.location.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openManagerModal = (manager) => {
    setSelectedManager(manager);
    setShowModal(true);
  };

  const handleSearch = (value) => {
    setSearchTerm(value);
  };

  const style = `
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    @keyframes zoomIn {
      from { opacity: 0; transform: scale(0.9); }
      to { opacity: 1; transform: scale(1); }
    }
    
    .managers-container {
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b);
      min-height: 100vh;
      padding-top: 80px;
      padding-bottom: 80px;
    }
    
    .managers-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
      gap: 30px;
      max-width: 1400px;
      margin: 0 auto;
      padding: 20px;
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.95);
      backdrop-filter: blur(12px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 25px;
      max-width: 500px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      animation: zoomIn 0.3s ease;
    }
    
    .modal-manager-image {
      width: 120px;
      height: 120px;
      border-radius: 50%;
      object-fit: cover;
      margin: 0 auto 15px;
      display: block;
      border: 3px solid #22c55e;
    }
    
    .modal-header {
      text-align: center;
      margin-bottom: 20px;
    }
    
    .modal-header h2 {
      color: white;
      margin: 0;
    }
    
    .modal-header p {
      color: #22c55e;
      margin: 5px 0 0;
    }
    
    .modal-info {
      margin-bottom: 15px;
    }
    
    .modal-info p {
      color: rgba(255,255,255,0.7);
      font-size: 0.85rem;
      margin: 8px 0;
    }
    
    .skills-container {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      margin: 15px 0;
    }
    
    .skill-badge {
      background: rgba(34,197,94,0.2);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 20px;
      padding: 4px 12px;
      font-size: 0.7rem;
      color: #4ade80;
    }
    
    .status-badge-modal {
      display: inline-block;
      padding: 4px 12px;
      border-radius: 20px;
      font-size: 0.7rem;
      font-weight: bold;
      margin-top: 10px;
    }
    
    .status-badge-modal.active {
      background: #22c55e;
      color: white;
    }
    
    .status-badge-modal.inactive {
      background: #ef4444;
      color: white;
    }
    
    .btn-visit {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 12px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      width: 100%;
      margin-top: 20px;
      transition: all 0.3s;
    }
    
    .btn-visit:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
    }
    
    .empty-state {
      text-align: center;
      padding: 50px;
      color: rgba(255,255,255,0.5);
    }
    
    .empty-state-icon {
      font-size: 4rem;
      margin-bottom: 15px;
      opacity: 0.5;
    }
    
    @media (max-width: 768px) {
      .managers-grid {
        grid-template-columns: 1fr;
        padding: 15px;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="managers-container">
        <div className="managers-grid">
          {filteredManagers.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">👨‍💼</div>
              <p>Aucun manager trouvé</p>
              <p style={{ fontSize: '0.8rem' }}>Essayez une autre recherche</p>
            </div>
          ) : (
            filteredManagers.map(manager => (
              <ManagerCard 
                key={manager.id}
                manager={manager}
                onClick={openManagerModal}
              />
            ))
          )}
        </div>
      </div>
      
      <FooterRecharche 
        type="managers"
        onSearch={handleSearch}
        placeholder="🔍 Rechercher un manager par nom, rôle ou ville..."
      />
      
      {showModal && selectedManager && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setShowModal(false)}>✕</button>
            <img src={selectedManager.profileImage} alt={selectedManager.name} className="modal-manager-image" />
            <div className="modal-header">
              <h2>{selectedManager.name}</h2>
              <p>👔 {selectedManager.role}</p>
              <span className={`status-badge-modal ${selectedManager.status}`}>
                {selectedManager.status === "active" ? "✅ Actif" : "⏸️ Inactif"}
              </span>
            </div>
            <div className="modal-info">
              <p>📍 {selectedManager.location}</p>
              <p>⭐ {selectedManager.rating} / 5</p>
              <p>👥 {selectedManager.employees} employés supervisés</p>
              <p>🏪 {selectedManager.restaurantCount} restaurant(s) géré(s)</p>
              <p>📅 {selectedManager.experience}</p>
              <p>📧 {selectedManager.email}</p>
              <p>📞 {selectedManager.phone}</p>
            </div>
            <div className="skills-container">
              {selectedManager.skills.map((skill, index) => (
                <span key={index} className="skill-badge">{skill}</span>
              ))}
            </div>
            <button className="btn-visit" onClick={() => alert(`Profil de ${selectedManager.name}`)}>
              👨‍💼 Voir le profil complet →
            </button>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
